// Fetch pending notifications from Memento API
const MEMENTO_TOKEN = '{{MEMENTO_API_TOKEN}}';
const NOTIF_LIB = 'mRERW8SrY';
const FIELD_IDS = '31,65,2,3,38,1,26,48,10'; // Status,Typ,ChatID,MsgID,Sprava,ZdrojKniz,ZdrojID,Retry,ThreadID

const url = `https://api.mementodatabase.com/v1/libraries/${NOTIF_LIB}/entries?token=${MEMENTO_TOKEN}&fields=${FIELD_IDS}&pageSize=100`;

let resp;
try {
    resp = await this.helpers.httpRequest({ method: 'GET', url, returnFullResponse: true, ignoreHttpStatusErrors: true });
} catch (e) {
    return [];
}

if (resp.statusCode === 429) {
    // Rate limited — skip this cycle
    return [];
}

const data = typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
const entries = (data.entries || []).filter(e => e.status !== 'deleted');

// Field ID mapping
const FMAP = {31:'status', 65:'typ', 2:'chatId', 3:'messageId', 38:'message', 1:'sourceLib', 26:'sourceId', 48:'retryCount', 10:'threadId'};

const pending = [];
for (const e of entries) {
    const fields = {};
    for (const f of (e.fields || [])) {
        const name = FMAP[f.id];
        if (name) fields[name] = f.value || '';
    }
    if (fields.status !== 'Čaká') continue;
    if (!fields.chatId) continue;                              // chatId vždy povinné
    if (fields.typ !== 'SEND' && !fields.messageId) continue; // EDIT/DELETE potrebujú messageId; SEND ešte nemá

    pending.push({
        json: {
            entryId: e.id,
            typ: fields.typ || '',
            chatId: fields.chatId,
            messageId: fields.messageId,
            message: fields.message || '',
            sourceLib: fields.sourceLib || '',
            sourceId: fields.sourceId || '',
            threadId: fields.threadId || ''
        }
    });
}

return pending.length > 0 ? pending : [];

// For each notification, create queue entries:
// 1. TG API call (DELETE/SEND/EDIT)
// 2. PATCH Notification status to Odoslané

const BOT_TOKEN = '{{TELEGRAM_BOT_TOKEN}}';
const MEMENTO_TOKEN = '{{MEMENTO_API_TOKEN}}';
const NOTIF_LIB = 'mRERW8SrY';

const items = $input.all();
const results = [];

for (const item of items) {
    const d = item.json;

    let tgUrl = '';
    let tgBody = {};
    let tgOperation = '';

    if (d.typ === 'DELETE') {
        tgUrl = `https://api.telegram.org/bot${BOT_TOKEN}/deleteMessage`;
        tgBody = { chat_id: d.chatId, message_id: parseInt(d.messageId) };
        tgOperation = 'DELETE_MSG';
    } else if (d.typ === 'SEND') {
        tgUrl = `https://api.telegram.org/bot${BOT_TOKEN}/sendMessage`;
        tgBody = { chat_id: d.chatId, text: d.message || 'Test', parse_mode: 'HTML' };
        if (d.threadId) tgBody.message_thread_id = parseInt(d.threadId);
        tgOperation = 'SEND_MSG';
    } else if (d.typ === 'EDIT') {
        tgUrl = `https://api.telegram.org/bot${BOT_TOKEN}/editMessageText`;
        tgBody = { chat_id: d.chatId, message_id: parseInt(d.messageId), text: d.message || '', parse_mode: 'HTML' };
        tgOperation = 'EDIT_MSG';
    } else {
        continue; // unknown type
    }

    results.push({
        json: {
            // TG call
            tgUrl,
            tgBody: JSON.stringify(tgBody),
            tgOperation,
            // For PATCH after TG
            entryId: d.entryId,
            // Source
            sourceLib: d.sourceLib,
            sourceId: d.sourceId
        }
    });
}

return results.length > 0 ? results : [];

